import React, { useState, useEffect, useCallback } from "react";
import css from "./EditTemplate.module.css";
import { useNotifications } from "../../utils/Notifications/Notifications";
import { apiClient } from "../../components/api/url";

import Editor from "react-simple-code-editor";
import { highlight, languages } from "prismjs/components/prism-core";
import "prismjs/components/prism-clike";
import "prismjs/components/prism-javascript";
import "prismjs/components/prism-css";
import "prismjs/components/prism-markup";
import "prismjs/themes/prism.css";

const htmlDecode = (input) => {
    const textarea = document.createElement('textarea');
    textarea.innerHTML = input;
    return textarea.value;
};

const openPreviewWindow = (htmlContent) => {
    const newWindow = window.open("", "_blank");

    if (newWindow) {
        const fullHtml = `<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>Email Preview</title>
    <style>
        body { margin: 0; padding: 20px; font-family: Arial, sans-serif; background-color: #f4f4f4; }
        .preview-container { max-width: 600px; margin: 0 auto; background-color: white; border: 1px solid #ddd; padding: 20px; box-shadow: 0 0 10px rgba(0,0,0,0.1); }
    </style>
</head>
<body>
    <div class="preview-container">
        ${htmlContent}
    </div>
</body>
</html>`;

        newWindow.document.write(fullHtml);
        newWindow.document.close();
    } else {
        alert("Could not open preview window. Please check your browser's pop-up blocker settings.");
    }
};

const EditTemplate = () => {
    const [allTemplates, setAllTemplates] = useState([]);
    const [filteredTemplates, setFilteredTemplates] = useState([]);
    const [selectedTemplateId, setSelectedTemplateId] = useState("");
    const [selectedTemplateContent, setSelectedTemplateContent] = useState("");
    const [templateSearchInput, setTemplateSearchInput] = useState("");
    const [showTemplateDropdown, setShowTemplateDropdown] = useState(false);
    const [isSaving, setIsSaving] = useState(false);
    const [editorValue, setEditorValue] = useState("");
    const { showNotification, showConfirmation } = useNotifications();

    const fetchAllTemplates = useCallback(async () => {
        try {
            const response = await apiClient.get("templates/gettemp");
            if (response.data && Array.isArray(response.data.templates)) {
                setAllTemplates(response.data.templates);
                setFilteredTemplates(response.data.templates);
            } else {
                console.error("Error loading templates:", response);
                setAllTemplates([]);
                setFilteredTemplates([]);
            }
        } catch (error) {
            console.error("Error loading templates:", error);
            setAllTemplates([]);
            setFilteredTemplates([]);
        }
    }, []);

    const fetchTemplateContent = useCallback(
        async (id) => {
            try {
                const response = await apiClient.get(`templates/gettemp/${id}`);
                if (response.data && response.data.template.tempText) {
                    const parser = new DOMParser();
                    const doc = parser.parseFromString(response.data.template.tempText, 'text/html');
                    const bodyElement = doc.body;

                    const processedTempText = bodyElement ? bodyElement.innerHTML : response.data.template.tempText;
                    setSelectedTemplateContent(processedTempText);
                    setEditorValue(processedTempText);
                    return processedTempText;
                } else {
                    showNotification("Failed to load template content.", "error");
                    return "";
                }
            } catch (error) {
                console.error("Error loading template content:", error);
                showNotification("Error loading template content.", "error");
                return "";
            }
        },
        [showNotification]
    );

    useEffect(() => {
        fetchAllTemplates();
    }, [fetchAllTemplates]);

    const handleTemplateSearchInputChange = (e) => {
        const value = e.target.value;
        setTemplateSearchInput(value);
        setShowTemplateDropdown(true);

        const lowerCaseValue = value.toLowerCase();
        const filtered = allTemplates.filter((template) =>
            template.tempName.toLowerCase().includes(lowerCaseValue)
        );
        setFilteredTemplates(filtered);

        const currentlySelectedTemplate = allTemplates.find(
            (t) => t.id === selectedTemplateId
        );
        if (
            currentlySelectedTemplate &&
            currentlySelectedTemplate.tempName.toLowerCase() !== lowerCaseValue
        ) {
            setSelectedTemplateId("");
            setEditorValue("");
        } else if (!value) {
            setSelectedTemplateId("");
            setEditorValue("");
        }
    };

    const handleTemplateSelect = useCallback(
        async (template) => {
            setTemplateSearchInput(template.tempName);
            setSelectedTemplateId(template.id);
            setShowTemplateDropdown(false);
            setFilteredTemplates([]);
            await fetchTemplateContent(template.id);
        },
        [fetchTemplateContent]
    );

    const handleClickOutside = useCallback(
        (e) => {
            if (
                e.target &&
                !e.target.closest(`.${css.templateSearchContainer}`) &&
                showTemplateDropdown
            ) {
                setShowTemplateDropdown(false);

                const selectedTemplate = allTemplates.find(
                    (t) => t.id === selectedTemplateId
                );
                if (selectedTemplate) {
                    if (templateSearchInput !== selectedTemplate.tempName) {
                        setTemplateSearchInput(selectedTemplate.tempName);
                    }
                } else {
                    setTemplateSearchInput("");
                }
                setFilteredTemplates(allTemplates);
            }
        },
        [
            showTemplateDropdown,
            templateSearchInput,
            selectedTemplateId,
            allTemplates,
        ]
    );

    useEffect(() => {
        document.addEventListener("mousedown", handleClickOutside);
        return () => {
            document.removeEventListener("mousedown", handleClickOutside);
        };
    }, [handleClickOutside]);

    const handlePreview = () => {
        if (!editorValue) {
            showNotification('Template body is empty. Cannot preview.', 'warning');
            return;
        }

        const decodedBody = htmlDecode(editorValue);

        openPreviewWindow(decodedBody);
    };

    const handleSave = async (e) => {
        e.preventDefault();
        if (!selectedTemplateId) {
            showNotification("Please select a template to save.", "error");
            return;
        }

        setIsSaving(true);
        try {
            const processedEditorValue = editorValue.replace(/&/g, '&amp;');

            const response = await apiClient.put(
                `templates/gettemp/${selectedTemplateId}`,
                {
                    tempText: processedEditorValue,
                }
            );

            if (response) {
                showNotification(
                    `Template "${templateSearchInput}" saved successfully!`,
                    "success"
                );
                setSelectedTemplateContent(processedEditorValue);
            } else {
                showNotification(
                    `Error saving template: Unknown error`,
                    "error"
                );
            }
        } catch (error) {
            showNotification("An error occurred while saving the template.", "error");
        } finally {
            setIsSaving(false);
        }
    };

    return (
        <div className={css.cont}>
            <h2 className={css.title}>Edit Template</h2>
            <form className={css.form} onSubmit={handleSave}>
                <label className={css.label}>
                    <span>Search Template by Name:</span>
                    <div
                        className={css.templateSearchContainer}
                        style={{ position: "relative" }}
                    >
                        <input
                            type="text"
                            name="templateSearch"
                            value={templateSearchInput}
                            onChange={handleTemplateSearchInputChange}
                            onFocus={() => setShowTemplateDropdown(true)}
                            placeholder="Start typing template name..."
                            autoComplete="off"
                            required
                        />
                        {showTemplateDropdown && filteredTemplates.length > 0 && (
                            <ul className={css.templateDropdown}>
                                {filteredTemplates.map((template) => (
                                    <li
                                        key={template.id}
                                        onClick={() => handleTemplateSelect(template)}
                                        className={css.dropdownItem}
                                    >
                                        {template.tempName} ({template.tempGeo || "none"}) - ID:{" "}
                                        {template.id}
                                    </li>
                                ))}
                            </ul>
                        )}
                        {showTemplateDropdown &&
                            filteredTemplates.length === 0 &&
                            templateSearchInput && (
                                <ul className={css.templateDropdown}>
                                    <li className={css.noResults}>
                                        No templates found for "{templateSearchInput}"
                                    </li>
                                </ul>
                            )}
                    </div>
                </label>

                {selectedTemplateId && (
                    <>
                        <p className={css.selectedTemplateInfo}>
                            Selected for editing: <strong>{templateSearchInput}</strong> (ID:{" "}
                            {selectedTemplateId})
                        </p>

                        <div className={css.editorContainer}>
                            <Editor
                                value={editorValue}
                                onValueChange={(code) => setEditorValue(code)}
                                highlight={(code) =>
                                    highlight(code, languages.markup, "markup")
                                }
                                padding={10}
                                className={css.editor}
                                style={{
                                    fontFamily: '"Fira code", "Fira Mono", monospace',
                                    fontSize: 12,
                                }}
                            />
                        </div>

                        <div style={{ display: 'flex', justifyContent: 'flex-start', gap: '10px', marginTop: '10px' }}>
                            <button
                                className={css.saveButton}
                                type="button"
                                onClick={handlePreview}
                                disabled={!editorValue}
                            >
                                Preview
                            </button>
                            <button
                                className={css.saveButton}
                                type="submit"
                                disabled={
                                    !selectedTemplateId ||
                                    isSaving ||
                                    selectedTemplateContent === editorValue
                                }
                            >
                                {isSaving ? "Saving..." : "Save Changes"}
                            </button>
                        </div>
                    </>
                )}
            </form>
        </div>
    );
};

export default EditTemplate;